document.addEventListener('DOMContentLoaded', function() {
  // Fase 1: init y KPIs (inmediato — sin charts)
  try { initBanner(); } catch(e) { console.error('initBanner:', e); }
  try { initControls(); } catch(e) { console.error('initControls:', e); }
  try { renderKPIs(); } catch(e) { console.error('renderKPIs:', e); }

  // Fase 2: charts principales (diferido para no bloquear el render inicial)
  setTimeout(function() {
    try { renderEvoChart(); } catch(e) { console.error('renderEvoChart:', e); }
    try { renderEvoTable(); } catch(e) { console.error('renderEvoTable:', e); }
    try { renderLocalChart(); } catch(e) { console.error('renderLocalChart:', e); }
    try { renderRubroChart(); } catch(e) { console.error('renderRubroChart:', e); }
  }, 0);

  // Fase 3: secciones pesadas (diferido extra) + ocultar overlay
  setTimeout(function() {
    try { renderUdsCharts(); } catch(e) { console.error('renderUdsCharts:', e); }
    try { renderErpCharts(); } catch(e) { console.error('renderErpCharts:', e); }
    try { renderTables(); } catch(e) { console.error('renderTables:', e); }
    try { renderProjection(); } catch(e) { console.error('renderProjection:', e); }
    var overlay = document.getElementById('loading');
    if (overlay) overlay.style.display = 'none';
  }, 50);
});

// =====================================================
// CARGADOR DE EXCEL (SheetJS) — actualización sin Python
// =====================================================
(function() {
  var LOCALES = ['R. Indarte','S.M.Cba','9deJulio','GralPaz','Peatonal','EntreRios',
                 'MLcordoba','MLCABA','MLBoerss','Nubexmayor','.COM','Deposito',
                 'TravelBlue','Naranja','Linio','Dafiti'];
  var RUBROS  = ['Carteras','Bebé','Mochilas','Equipaje','Billeteras','Librería','Carpetas',
                 'Paraguas','Accesorios','Juguetería','CartuchLunch','Textil','Bijou',
                 'DecoHome','Indumentaria','Beauty','Aromáticos','Tecnología','TextilHogar','AccPelo'];
  var MESES   = {Ene:1,Feb:2,Mar:3,Abr:4,May:5,Jun:6,Jul:7,Ago:8,Sep:9,Oct:10,Nov:11,Dic:12};
  var NOMBRES_MESES = ['','Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  var _wb = null; // workbook guardado para migración

  function parseExcel(wb) {
    var ws = wb.Sheets['VENTAS MENSUALES'];
    var rows = XLSX.utils.sheet_to_json(ws, {header:1, defval:null});
    var raw = [], headerIdx = -1;
    for (var i=0; i<rows.length; i++) { if (rows[i][0]==='Período'){headerIdx=i;break;} }
    for (var i=headerIdx+1; i<rows.length; i++) {
      var row=rows[i]; if(!row[0]) continue;
      var parts=String(row[0]).split('-'); if(parts.length!==2) continue;
      var key=parts[0].substring(0,3); key=key.charAt(0).toUpperCase()+key.slice(1).toLowerCase();
      var mesN=MESES[key]; if(!mesN) continue;
      var yr=parseInt(parts[1]); if(yr<100) yr+=2000;
      var loc={}; LOCALES.forEach(function(l,j){if(row[j+1]) loc[l]=parseFloat(row[j+1]);});
      var rub={}; RUBROS.forEach(function(r,j){if(row[j+19]) rub[r]=parseFloat(row[j+19]);});
      raw.push({fecha:yr+'-'+(mesN<10?'0':'')+mesN,año:yr,mes:mesN,locales:loc,rubros:rub,
                total:row[17]?parseFloat(row[17]):0});
    }
    var ws2=wb.Sheets['DETALLE ERP'];
    var rows2=XLSX.utils.sheet_to_json(ws2,{header:1,defval:null});
    var det=[],h2=-1;
    for(var i=0;i<rows2.length;i++){if(rows2[i][0]==='Año'){h2=i;break;}}
    for(var i=h2+1;i<rows2.length;i++){
      var r=rows2[i]; if(!r[0]) continue;
      try{det.push({a:parseInt(r[0]),m:parseInt(r[1]),l:r[3]?String(r[3]):'',
                    r:r[4]?String(r[4]):'',v:r[6]?parseFloat(r[6]):0,u:r[7]?parseInt(r[7]):0});}catch(e){}
    }
    // === ZONA PEGAR ERP → integrar meses nuevos directamente ===
    var wsZ = wb.Sheets['ZONA PEGAR ERP'];
    if (wsZ) {
      var rowsZ = XLSX.utils.sheet_to_json(wsZ, {header:1, defval:null});
      var hZ = -1;
      for (var i=0; i<rowsZ.length; i++) {
        var v0 = rowsZ[i][0];
        if (v0 && String(v0).toLowerCase()==='año') { hZ=i; break; }
      }
      if (hZ >= 0) {
        // Agrupar por (año, mes, local, rubro) y sumar
        var zonaMap = {};
        var LOCAL_MAP={'105':'Peatonal','5555':'Peatonal','107':'Deposito','113':'Deposito','3333':'Deposito','109':'R. Indarte','9999':'R. Indarte','200':'TravelBlue','R. Indarte':'R. Indarte','R. Indarte':'R. Indarte'};
        for (var i=hZ+1; i<rowsZ.length; i++) {
          var r=rowsZ[i]; if(!r[0]) continue;
          var a=parseInt(r[0]), m=parseInt(r[1]);
          var lRaw=r[2]?String(r[2]):''; var l=LOCAL_MAP[lRaw]||lRaw; var rb=r[3]?String(r[3]):'';
          // PrecioUnitarioImpuesto (col 5) × Cantidad (col 6) = total con IVA
          var precio=r[5]?parseFloat(r[5]):0;
          var cant=r[6]?parseFloat(r[6]):0;
          var key=a+'-'+m+'-'+l+'-'+rb;
          if (!zonaMap[key]) zonaMap[key]={a:a,m:m,l:l,r:rb,v:0,u:0};
          zonaMap[key].v += precio * cant;
          zonaMap[key].u += cant;
        }
        // Identificar meses presentes en ZONA PEGAR ERP
        var zonaMeses={};
        Object.values(zonaMap).forEach(function(x){ zonaMeses[x.a+'-'+x.m]=true; });
        // Quitar esos meses de DETALLE ERP (evitar duplicados)
        det = det.filter(function(d){ return !zonaMeses[d.a+'-'+d.m]; });
        // Agregar los datos de ZONA PEGAR ERP
        Object.values(zonaMap).forEach(function(x){ det.push(x); });
      }
    }
    return {raw:raw,det:det};
  }

  function recargar(newRaw, newDet) {
    RAW.length=0; newRaw.forEach(function(x){RAW.push(x);});
    DET.length=0; newDet.forEach(function(x){DET.push(x);});
    document.querySelectorAll('canvas').forEach(function(c){
      var ch=Chart.getChart(c); if(ch) ch.destroy();
    });
    try{initBanner();}catch(e){}
    try{initControls();}catch(e){}
    try{renderKPIs();}catch(e){}
    setTimeout(function(){
      try{renderEvoChart();}catch(e){}
      try{renderEvoTable();}catch(e){}
      try{renderLocalChart();}catch(e){}
      try{renderRubroChart();}catch(e){}
    },0);
    setTimeout(function(){
      try{renderUdsCharts();}catch(e){}
      try{renderErpCharts();}catch(e){}
      try{renderTables();}catch(e){}
      try{renderProjection();}catch(e){}
    },50);
  }

  function descargarHTML() {
    var rawJ=JSON.stringify(RAW), detJ=JSON.stringify(DET);
    fetch(location.href).then(function(r){return r.text();}).then(function(src){
      var i1=src.indexOf('const RAW = ['),j1=src.indexOf('];',i1)+2;
      src=src.substring(0,i1)+'const RAW = '+rawJ+';'+src.substring(j1);
      var i2=src.indexOf('const DET=['),j2=src.indexOf('];',i2)+2;
      src=src.substring(0,i2)+'const DET='+detJ+';'+src.substring(j2);
      var ts=new Date().toLocaleDateString('es-AR');
      src=src.replace('</body>','<div style="text-align:center;padding:6px;font-size:11px;color:#94A3B8">Actualizado el '+ts+'</div></body>');
      var a=document.createElement('a');
      a.href=URL.createObjectURL(new Blob([src],{type:'text/html'}));
      a.download='index.html'; a.click();
    }).catch(function(){
      alert('Para descargar, abrí el dashboard desde la URL de Netlify, no como archivo local.');
    });
  }

  window.addEventListener('DOMContentLoaded',function(){
    var panel=document.createElement('div');
    panel.innerHTML='<div id="_xlBtn" style="position:fixed;bottom:22px;right:22px;z-index:9999;background:#1E3A5F;color:#fff;border:none;border-radius:8px;padding:10px 18px;cursor:pointer;font-size:13px;font-weight:700;box-shadow:0 4px 14px rgba(0,0,0,.35)" onclick="document.getElementById(\'_xlBox\').style.display=\'block\';this.style.display=\'none\'">📂 Actualizar Excel</div><div id="_xlBox" style="display:none;position:fixed;bottom:22px;right:22px;z-index:9999;background:#fff;border-radius:12px;padding:22px 24px;box-shadow:0 8px 32px rgba(0,0,0,.2);min-width:300px"><p style="margin:0 0 6px;font-weight:700;color:#1E293B;font-size:14px">Actualizar datos</p><p style="margin:0 0 14px;font-size:12px;color:#64748B">Seleccioná CINDY_MAESTRO.xlsx</p><input type="file" id="_xlFile" accept=".xlsx" style="display:block;margin-bottom:14px;font-size:13px;width:100%"><button id="_xlLoad" style="background:#6366F1;color:#fff;border:none;border-radius:6px;padding:9px 0;font-size:13px;font-weight:700;width:100%;cursor:pointer;margin-bottom:8px">✓ Cargar y actualizar vista</button><button id="_xlMigrar" style="display:none;background:#F59E0B;color:#fff;border:none;border-radius:6px;padding:9px 0;font-size:13px;font-weight:700;width:100%;cursor:pointer;margin-bottom:8px">📥 Migrar ZONA PEGAR → DETALLE ERP y descargar Excel</button><button id="_xlDown" style="background:#10B981;color:#fff;border:none;border-radius:6px;padding:9px 0;font-size:13px;font-weight:700;width:100%;cursor:pointer;margin-bottom:10px">⬇ Descargar index.html actualizado</button><button onclick="document.getElementById(\'_xlBox\').style.display=\'none\';document.getElementById(\'_xlBtn\').style.display=\'block\'" style="background:none;border:none;color:#94A3B8;font-size:12px;cursor:pointer">Cerrar</button><div id="_xlStatus" style="margin-top:8px;font-size:12px;color:#6366F1"></div></div>';
    document.body.appendChild(panel);
    document.getElementById('_xlMigrar').addEventListener('click',function(){
      if(!_wb){alert('Cargá el Excel primero');return;}
      var st=document.getElementById('_xlStatus');
      try{
        var wsZ=_wb.Sheets['ZONA PEGAR ERP'];
        var rowsZ=XLSX.utils.sheet_to_json(wsZ,{header:1,defval:null});
        var hZ=-1;
        for(var i=0;i<rowsZ.length;i++){if(rowsZ[i][0]&&String(rowsZ[i][0]).toLowerCase()==='año'){hZ=i;break;}}
        if(hZ<0){alert('No se encontró encabezado en ZONA PEGAR ERP');return;}

        // Agrupar ZONA PEGAR ERP por (año,mes,local,rubro)
        var zonaMap={};
        var LOCAL_MAP={'105':'Peatonal','5555':'Peatonal','107':'Deposito','113':'Deposito','3333':'Deposito','109':'R. Indarte','9999':'R. Indarte','200':'TravelBlue','R. Indarte':'R. Indarte','R. Indarte':'R. Indarte'};
        for(var i=hZ+1;i<rowsZ.length;i++){
          var r=rowsZ[i]; if(!r[0]) continue;
          var a=parseInt(r[0]),m=parseInt(r[1]);
          var lRaw=r[2]?String(r[2]):''; var l=LOCAL_MAP[lRaw]||lRaw; var rb=r[3]?String(r[3]):'';
          var vta=r[4]?parseFloat(r[4]):0, imp=r[5]?parseFloat(r[5]):0, cant=r[6]?parseFloat(r[6]):0;
          var key=a+'-'+m+'-'+l+'-'+rb;
          if(!zonaMap[key]) zonaMap[key]={a:a,m:m,mn:NOMBRES_MESES[m]||'',l:l,r:rb,vSinIva:0,vConIva:0,u:0};
          zonaMap[key].vSinIva += vta*cant;
          zonaMap[key].vConIva += imp*cant;
          zonaMap[key].u += cant;
        }

        // Meses a migrar
        var zonaMeses={};
        Object.values(zonaMap).forEach(function(x){zonaMeses[x.a+'-'+x.m]=true;});

        // Leer DETALLE ERP y quitar meses que vienen en ZONA
        var wsDet=_wb.Sheets['DETALLE ERP'];
        var rowsDet=XLSX.utils.sheet_to_json(wsDet,{header:1,defval:null});
        var hDet=-1;
        for(var i=0;i<rowsDet.length;i++){if(rowsDet[i][0]==='Año'){hDet=i;break;}}
        var encabezados=rowsDet.slice(0,hDet+1);
        var filasFiltradas=rowsDet.slice(hDet+1).filter(function(r){
          return r[0] && !zonaMeses[parseInt(r[0])+'-'+parseInt(r[1])];
        });

        // Agregar filas migradas de ZONA PEGAR ERP
        Object.values(zonaMap).forEach(function(x){
          filasFiltradas.push([x.a,x.m,x.mn,x.l,x.r,
            Math.round(x.vSinIva*100)/100,
            Math.round(x.vConIva*100)/100,
            Math.round(x.u)]);
        });

        // Reconstruir hoja DETALLE ERP
        var newDetSheet=XLSX.utils.aoa_to_sheet(encabezados.concat(filasFiltradas));
        _wb.Sheets['DETALLE ERP']=newDetSheet;

        // Limpiar ZONA PEGAR ERP (dejar solo encabezado)
        var headerZona=rowsZ.slice(0,hZ+1);
        _wb.Sheets['ZONA PEGAR ERP']=XLSX.utils.aoa_to_sheet(headerZona);

        // Descargar Excel actualizado
        XLSX.writeFile(_wb,'CINDY_MAESTRO.xlsx');

        st.textContent='✓ Migración completada — '+Object.keys(zonaMap).length+' registros movidos a DETALLE ERP';
        st.style.color='#6366F1';
        document.getElementById('_xlMigrar').style.display='none';
      }catch(err){st.textContent='Error en migración: '+err.message;st.style.color='#F43F5E';}
    });

    document.getElementById('_xlLoad').addEventListener('click',function(){
      var file=document.getElementById('_xlFile').files[0];
      if(!file){alert('Seleccioná un archivo .xlsx primero');return;}
      var st=document.getElementById('_xlStatus'); st.textContent='Leyendo...';
      var reader=new FileReader();
      reader.onload=function(e){
        try{
          var wb=XLSX.read(e.target.result,{type:'array'});
          _wb = wb;
          var data=parseExcel(wb);
          recargar(data.raw,data.det);
          // Mostrar botón de migración si hay datos en ZONA PEGAR ERP
          var wsZ=wb.Sheets['ZONA PEGAR ERP'];
          var rowsZ=wsZ?XLSX.utils.sheet_to_json(wsZ,{header:1,defval:null}):[];
          var tieneZona=rowsZ.filter(function(r){return r[0]&&String(r[0]).toLowerCase()!=='año';}).length>0;
          document.getElementById('_xlMigrar').style.display=tieneZona?'block':'none';
          st.textContent='✓ '+data.raw.length+' meses | '+data.det.length+' registros cargados'+(tieneZona?' — hay datos nuevos en ZONA PEGAR ERP':'');
          st.style.color='#10B981';
        }catch(err){st.textContent='Error: '+err.message;st.style.color='#F43F5E';}
      };
      reader.readAsArrayBuffer(file);
    });
    document.getElementById('_xlDown').addEventListener('click',descargarHTML);
  });
})();
